B.OZ=new A.F(B.k,[u.A,"Studiengang: Wirtschaftsingenieurwesen (B.Sc.)\nProfil: Management elektrischer Systeme"],t.w)
B.Od=new A.F(B.k,[u.g,"Workshop zu 3D-Druck und Laser-Holzschneider"],t.w)
B.Nf=new A.F(B.k,["Programming of a Micro Controller ","Programmierung eines Mikrocontrollers "],t.w)
